/* System V style (interprets backslash, no -n): */
/* echo "a\nb" -> "a" newline "b" */
/* echo -n hello -> "-n hello" */

/* POSIX compromise: both behaviors allowed, prefer printf */

for(i=1; i<argc; i++) {
    fputs(argv[i], stdout);    /* not printf("%s", argv[i]) */
