/* Priority: exp() < e1() < e2() < e3() */

struct anode *exp() {   /* -o (OR) */
    p1 = e1();
    if(EQ(nxtarg(), "-o"))
        return(mk(or, p1, exp()));
    ...
}
struct anode *e1() {  /* -a (AND, implicit) */
    p1 = e2();
    a = nxtarg();
    if(EQ(a, "-a")) goto And;
    if(EQ(a, "(") || EQ(a, "!") || (*a=='-' && !EQ(a, "-o"))) {
        --Ai;
        goto And;       /* implicit AND */
    }
    ...
}
struct anode *e2() {  /* ! (NOT) */
    if(EQ(nxtarg(), "!"))
        return(mk(not, e3(), 0));
    return(e3());
}
struct anode *e3() {  /* parens and predicates */
    if(EQ(a, "(")) { p1 = exp(); ... return(p1); }
    if(EQ(a, "-name"))  return(mk(glob, ...));
    if(EQ(a, "-mtime")) return(mk(mtime, ...));
    /* ... 11 predicates ... */
}

descend(name, fname, exlist) {
    if(stat(fname, &Statb)<0) {
        fprintf(stderr, "find: bad status\n");
        return(0);
    }
    (*exlist->F)(exlist);          /* evaluate predicates */
    if((Statb.st_mode&S_IFMT)!=S_IFDIR)
        return(1);                  /* not a dir */

    if(chdir(fname) == -1) return(0);

    for(offset=0 ; offset < dirsize ; offset += 512) {
        /* read 512-byte directory block */
        read(dir, (char *)dentry, dsize);
        for(dp=dentry, entries=dsize>>4; entries; --entries, ++dp) {
            if(dp->d_ino==0
            || (dp->d_name[0]=='.' && dp->d_name[1]=='\0')
            || (dp->d_name[0]=='.' && dp->d_name[1]=='.' && dp->d_name[2]=='\0'))
                continue;            /* skip . and .. */
            /* build path, recurse */
            descend(name, dp->d_name, exlist);
        }
    }
}

doex(com) {
    static char *nargv[50];
    static ccode;

    ccode = np = 0;
    while (na=Argv[com++]) {
        if(strcmp(na, ";")==0) break;
        if(strcmp(na, "{}")==0) nargv[np++] = Pathname;
        else nargv[np++] = na;
    }
    nargv[np] = 0;
    if(fork()) /*parent*/ wait(&ccode);
    else { /*child*/
        chdir(Home);
        execvp(nargv[0], nargv, np);
        exit(1);
    }
    return(ccode ? 0:1);
}

ok(p) {              /* interactive -ok */
    fprintf(stderr, "< %s ... %s > ?   ", Argv[p->com], Pathname);
    if((c=getchar())=='y') yes = 1;
    while(c!='\n') c = getchar();
    if(yes) return(doex(p->com));
    return(0);
}

struct anode {
    int (*F)();              /* predicate function */
    struct anode *L, *R;     /* left/right children */
} Node[100];
int Nn;

struct anode *mk(f, l, r) int (*f)(); ... {
    Node[Nn].F = f;
    Node[Nn].L = l;
    Node[Nn].R = r;
    return(&(Node[Nn++]));
}

/* AST evaluation: */
(*exlist->F)(exlist);   /* call root predicate */

/* and/or/not recurse into children: */
and(p) struct anode *p; {
    return(((*p->L->F)(p->L)) && ((*p->R->F)(p->R)) ? 1 : 0);
}
or(p) struct anode *p; {
    return(((*p->L->F)(p->L)) || ((*p->R->F)(p->R)) ? 1 : 0);
}
not(p) struct anode *p; {
    return(!((*p->L->F)(p->L)));
}

/* 11 stat-based predicates: */
mtime(p)  /* -mtime N: modify time (days) */
atime(p)  /* -atime N: access time (days) */
user(p)   /* -user U: owner uid */
group(p)  /* -group G: group gid */
size(p)   /* -size N: file size (512-byte blocks) */
perm(p)   /* -perm M: permission bits */
links(p)  /* -links N: link count */
type(p)   /* -type t: f/d/b/c (file/dir/block/char) */
ino(p)    /* -inum N: inode number */
newer()   /* -newer file: newer than reference */
glob(p)   /* -name pattern: shell glob match */

/* 3-way comparison shared by numeric predicates: */
scomp(a, b, s) {
    if(s == '+') return(a > b);
    if(s == '-') return(a < b);
    return(a == b);
}

/* Example implementations: */
size(p) {
    return(scomp((int)((Statb.st_size+511)>>9), p->sz, p->s));
}
perm(p) {
    i = (p->s=='-') ? p->per : 07777;
    return((Statb.st_mode & i & 07777) == p->per);
}
